var lazyanalytics = false;

function loadGTM() {
  if (lazyanalytics) return;
  lazyanalytics = true;

  window.dataLayer = window.dataLayer || [];
  dataLayer.push({ 'gtm.start': new Date().getTime(), event: 'gtm.js' });

  var f = document.getElementsByTagName('script')[0];
  var j = document.createElement('script');
  j.async = true;
  j.src = 'https://www.googletagmanager.com/gtm.js?id=GTM-PQPPSM6J';
  f.parentNode.insertBefore(j, f);

  window.removeEventListener('scroll', onLazyTrigger, true);
  window.removeEventListener('mousemove', onLazyTrigger, true);
  window.removeEventListener('touchstart', onLazyTrigger, true);
}

function onLazyTrigger() {
  loadGTM();
}

window.addEventListener('scroll', onLazyTrigger, true);
window.addEventListener('mousemove', onLazyTrigger, true);
window.addEventListener('touchstart', onLazyTrigger, true);
