/**/

/* Global Helpers (Modern ES6+) */
const qs = (selector, parent = document) => parent.querySelector(selector);
const qsa = (selector, parent = document) => Array.from(parent.querySelectorAll(selector));

const showElement = el => { if (el) el.style.display = ""; };
const hideElement = el => { if (el) el.style.display = "none"; };

const getFavorites = () => {
  try { return JSON.parse(localStorage.getItem("lmydfavorites")) || []; } 
  catch (e) { return []; }
};
const saveFavorites = favs => {
  try { localStorage.setItem("lmydfavorites", JSON.stringify(favs)); } 
  catch (e) { console.warn("Local storage diblokir"); }
};
const broadcastStorageChange = () => {
  try { localStorage.setItem("broadcast", Date.now()); } 
  catch (e) {}
};

/* Bootstrap Tooltip Helpers - Diperbarui */
const initTooltip = (el, title) => {
  if (!el || !window.bootstrap?.Tooltip) return;

  // Hancurkan tooltip lama jika ada
  bootstrap.Tooltip.getInstance(el)?.dispose();

  if (title) {
    el.setAttribute("title", title);
    el.setAttribute("data-bs-title", title);
  }

  // PERBAIKAN: Tambahkan { trigger: 'hover' } agar tidak nyangkut saat diklik!
  new bootstrap.Tooltip(el, { trigger: 'hover' });
};

const showTooltip = el => {
  if (!el || !window.bootstrap?.Tooltip) return;
  (bootstrap.Tooltip.getInstance(el) || new bootstrap.Tooltip(el, { trigger: 'hover' })).show();
};

const hideTooltip = el => {
  if (!el || !window.bootstrap?.Tooltip) return;
  bootstrap.Tooltip.getInstance(el)?.hide();
};

/* Alert Popup */
const showZpopAlert = (message, isError = false) => {
  const alertEl = qs("#zpopAlert"), msgEl = qs("#zpopAlertMessage");
  if (!alertEl || !msgEl) return;

  msgEl.textContent = message;
  alertEl.style.backgroundColor = isError ? "rgba(255, 0, 0, 0.8)" : "rgba(90, 34, 139, 0.8)";
  alertEl.classList.add("show");

  setTimeout(() => alertEl.classList.remove("show"), 2500);
};

/* Remove ?m=1 From Blogger Mobile URL */
if (window.location.search.includes("m=1")) {
  window.history.replaceState({}, document.title, window.location.href.split("?m=1")[0]);
}

/* Back To Top Button */
document.addEventListener("scroll", () => {
  const scrollTop = document.documentElement.scrollTop || document.body.scrollTop;
  qsa(".zisToTop").forEach(btn => btn.classList.toggle("show", scrollTop > 300));
});

/* Favorite System Core */
const updateFavoriteUI = () => {
  const count = getFavorites().length;
  const countDisplay = qs("#favorite-count"), numberDisplay = qs("#favorite-number"), favIcon = qs("#favorite-icon");

  if (countDisplay && numberDisplay) {
    showElement(countDisplay);
    count > 0 ? (numberDisplay.textContent = count, showElement(numberDisplay)) : hideElement(numberDisplay);
  }

  if (favIcon) {
    favIcon.setAttribute("fill", count > 0 ? "currentColor" : "none");
    favIcon.innerHTML = '<use href="#bmk"></use>';
  }
};

const updateFavoriteButton = () => {
  const favs = getFavorites();
  qsa(".favorite-btn").forEach(btn => {
    const isFav = favs.some(item => item.id === btn.dataset.id);
    bootstrap.Tooltip?.getInstance(btn)?.dispose();
    btn.innerHTML = `<svg width="18" height="18" aria-hidden="true"><use href="#${isFav ? 'bmkremove' : 'bmkadd'}"></use></svg>`;
    initTooltip(btn, isFav ? "Remove Bookmark" : "Bookmark this Post");
  });
};
window.updateFavoriteButton = updateFavoriteButton;

const removeFavorite = id => {
  saveFavorites(getFavorites().filter(fav => fav.id !== id));
  showZpopAlert("Removed Bookmark.");
  broadcastStorageChange();
  updateModalContent();
  updateFavoriteUI();
  updateFavoriteButton();
};

const toggleFavorite = (id, judul, link, img) => {
  if (!window.localStorage) return alert("Sorry, localStorage is not supported in your browser.");

  const favs = getFavorites();
  const index = favs.findIndex(item => item.id === id);

  if (index === -1) {
    favs.push({ id, judul, link, img });
    showZpopAlert("Added to Bookmarks!");
  } else {
    favs.splice(index, 1);
    showZpopAlert("Removed Bookmark.");
  }

  saveFavorites(favs);
  updateFavoriteButton(); 
  updateFavoriteUI();
  updateModalContent(); 
  broadcastStorageChange();
};

/* Modal Content Renderer */
const updateModalContent = () => {
  const favs = getFavorites(), list = qs("#modal-favorite-list"), footerBtns = qs("#btn-fav"), table = qs("#modal-table");
  if (!list || !footerBtns) return;

  list.innerHTML = ""; footerBtns.innerHTML = "";

  if (!favs.length) {
    list.innerHTML = `
      <tr><td colspan="4" class="text-center"><svg class="svg5-zis bi"><use href="#sedih"></use></svg></td></tr>
      <tr><td colspan="4" class="text-center text-muted">Click Favorite Button <svg class="svg-zis bi"><use href="#bmkadd"></use></svg> to Add Bookmark Post.</td></tr>`;

    footerBtns.innerHTML = '<button class="btn btn-sm btn-primary rounded-1" onclick="window.location.href=\'/search?max-results=4\'">View All Posts</button>';
    return;
  }

  if (window.location.pathname === "/p/bookmarks-post.html") {
    if (table) table.style.display = "none";
    list.innerHTML = '<p class="text-center fw-bold mt-3">You are currently on the bookmarks page</p>';
    return;
  }

  list.innerHTML = favs.slice(0, 5).map((item, index) => `
    <tr>
      <td class="text-center align-middle">${index + 1}</td>
      <td class="text-center align-middle"><a href="${item.link}" target="_blank"><img class="img-fluid rounded-1" style="height:50px;width:80px;" src="${item.img}" alt="${item.judul}"></a></td>
      <td class="align-middle"><a href="${item.link}">${item.judul}</a></td>
      <td class="text-center align-middle"><button class="sampahFav btn btn-link border-0 py-2 putih" data-id="${item.id}" title="Remove bookmark"><svg width="16" height="16" aria-hidden="true"><use href="#bmksampah"></use></svg></button></td>
    </tr>`).join("");

  qsa(".sampahFav", list).forEach(btn => initTooltip(btn));

  if (favs.length > 5) {
    footerBtns.innerHTML = `<a class="btn btn-sm btn-primary" onclick="window.location.href='/p/bookmarks-post.html'">View All Bookmarked Posts (+${favs.length - 5})</a>`;
  }
};

/* Sync Bookmark Across Tabs */
window.addEventListener("storage", e => {
  if (e.key === "broadcast") {
    updateFavoriteButton(); updateFavoriteUI(); updateModalContent();
    if (window.location.pathname.includes("/p/bookmarks-post.html") && typeof loadFullFavorites === "function") loadFullFavorites();
  }
});

/* Init Global Script */
document.addEventListener("DOMContentLoaded", () => {
  /* Hide Images */
  qsa("img.hilang").forEach(img => { img.classList.remove("hilang"); img.classList.add("d-none"); });

  if (!localStorage.getItem("lmydfavorites")) saveFavorites([]);

  /* Cookie Consent */
  const cookieToast = qs("#cookieConsentToast");
  if (cookieToast && window.bootstrap?.Toast && !localStorage.getItem("cookieConsentAccepted")) {
    new bootstrap.Toast(cookieToast).show();
    qs(".btn-close", cookieToast)?.addEventListener("click", () => localStorage.setItem("cookieConsentAccepted", "true"));
  }

  /* Label Collapse */
  const labelCollapse = qs("#labelCollapse"), toggleBtn = qs("#toggleButton"), hiddenCount = qs("#hiddenCount");
  if (hiddenCount) hiddenCount.textContent = qsa(".label-item").length - 10;

  if (labelCollapse && toggleBtn) {
    labelCollapse.addEventListener("shown.bs.collapse", () => toggleBtn.textContent = "Show less...");
    labelCollapse.addEventListener("hidden.bs.collapse", () => toggleBtn.textContent = "Show more...");
  }

  /* Hamburger Menu */
  const burger = qs("#hamburgerIcon"), menu = qs("#menuContainer"), closeBtn = qs("#closeMenu");
  if (burger && menu && closeBtn) {
    burger.addEventListener("click", () => {
      menu.classList.add("show-menu"); menu.classList.remove("hide-menu"); burger.style.display = "none";
    });
    closeBtn.addEventListener("click", e => {
      e.preventDefault();
      menu.classList.remove("show-menu"); menu.classList.add("hide-menu"); burger.style.display = "block";
    });
  }

  /* Tooltip Global Listeners */
  qsa("[title]").forEach(el => initTooltip(el));

  const getClosestTitle = e => e.target?.closest?.("[title]");
  document.addEventListener("mouseenter", e => showTooltip(getClosestTitle(e)), true);
  document.addEventListener("mouseleave", e => hideTooltip(getClosestTitle(e)), true);
  document.addEventListener("click", e => hideTooltip(getClosestTitle(e)));

  /* Modal Triggers */
  qs("#favorite-icon")?.addEventListener("click", () => {
    const modalEl = qs("#favoritesModal");
    if (modalEl && window.bootstrap?.Modal) {
      updateModalContent();
      new bootstrap.Modal(modalEl).show();
    }
  });

  qs("#modal-favorite-list")?.addEventListener("click", e => {
    const btn = e.target.closest(".sampahFav");
    if (btn) { hideTooltip(btn); removeFavorite(btn.dataset.id); }
  });

  updateFavoriteButton(); updateFavoriteUI(); updateModalContent();
});

/* Global Bookmark Button Click Listener */
document.addEventListener("click", e => {
  const btn = e.target.closest(".favorite-btn");
  if (btn) {
    e.preventDefault();
    toggleFavorite(btn.dataset.id, btn.dataset.judul, btn.dataset.link, btn.dataset.img);
  }
});

